void findRangeK_parallel(	long height,
							knode *knodes,
							long tmp_0,
							long *currKnode,
							long *offset,
							long *lastKnode,
							long *offset_2,
							int *start,
							int *end,
							int *Recstart, 
							int *Reclen,
							int count,
							int order)
{
	int threadsPerBlock = 1024 > order ? order : 1024;

	#pragma omp parallel num_threads(count)
	{
		int bid = omp_get_thread_num();

		if (bid < count) {
			int thid;
			long local_currKnode = currKnode[bid];
			long local_offset = offset[bid];
			long local_lastKnode = lastKnode[bid];
			long local_offset_2 = offset_2[bid];
			int local_start = start[bid];
			int local_end = end[bid];

			int i;
			for(i = 0; i < height; i++){

				for(thid = 0; thid < threadsPerBlock; thid++){
					if((knodes[local_currKnode].keys[thid] <= local_start) && (knodes[local_currKnode].keys[thid+1] > local_start)){
						if(knodes[local_currKnode].indices[thid] < tmp_0){
							local_offset = knodes[local_currKnode].indices[thid];
						}
					}
					if((knodes[local_lastKnode].keys[thid] <= local_end) && (knodes[local_lastKnode].keys[thid+1] > local_end)){
						if(knodes[local_lastKnode].indices[thid] < tmp_0){
							local_offset_2 = knodes[local_lastKnode].indices[thid];
						}
					}
				}

				local_currKnode = local_offset;
				local_lastKnode = local_offset_2;
			}

			for(thid = 0; thid < threadsPerBlock; thid++){
				if(knodes[local_currKnode].keys[thid] == local_start){
					Recstart[bid] = knodes[local_currKnode].indices[thid];
				}
			}

			for(thid = 0; thid < threadsPerBlock; thid++){
				if(knodes[local_lastKnode].keys[thid] == local_end){
					Reclen[bid] = knodes[local_lastKnode].indices[thid] - Recstart[bid] + 1;
				}
			}
		}
	}
}

